mapper.select:
select r.task_id, r.trace_id, r.document_id, t.file_name, t.document_type, t.department_id, t.source_type, r.status as result_status, case r.need_review when '1' then '待复核' else '自动通过' end as review_status, r.target_table, r.mapping_profile, r.field_count, r.overall_confidence, r.created_at, r.updated_at from extract_result_record r left join extract_task t on r.task_id = t.task_id
and (r.task_id like #{keywordLike} or r.trace_id like #{keywordLike} or r.document_id like #{keywordLike} or t.file_name like #{keywordLike})
and t.document_type = #{query.documentType}
and t.department_id = #{query.departmentId}
and t.source_type = #{query.sourceType}
and r.status = #{query.resultStatus}
order by r.updated_at desc

mapper.insert:
insert into extract_result_record (
    id, task_id, trace_id, document_id, config_id, result_json, confidence_json,
    overall_confidence, need_review, status, field_count, target_table, mapping_profile,
    created_at, updated_at
) values (
    #{id}, #{taskId}, #{traceId}, #{documentId}, #{configId}, #{resultJson}, #{confidenceJson},
    #{overallConfidence}, #{needReview}, #{status}, #{fieldCount}, #{targetTable}, #{mappingProfile},
    #{createdAt}, #{updatedAt}
)
